// Domain Service: Contact Validation
class ContactValidationService {
  constructor() {
    this.emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  }

  validateContacts(contacts) {
    if (!Array.isArray(contacts)) {
      throw new Error('Contacts must be an array');
    }

    return contacts.map((contact, index) => {
      const validation = this.validateSingleContact(contact, index);
      return {
        ...contact,
        validation,
        processingId: this.generateProcessingId(),
        processedAt: new Date().toISOString()
      };
    });
  }

  validateSingleContact(contact, index) {
    const errors = [];
    const warnings = [];

    // Required field validation
    if (!contact.firstName?.trim()) {
      errors.push('firstName is required');
    }
    if (!contact.lastName?.trim()) {
      errors.push('lastName is required');
    }

    // Email format validation
    const email = contact.email?.trim();
    const hasValidEmail = email && this.emailRegex.test(email);
    const hasCompany = contact.company?.trim();

    if (!hasValidEmail && !hasCompany) {
      errors.push('Either valid email or company name is required for enrichment');
    }

    if (email && !hasValidEmail) {
      warnings.push('Email format appears invalid');
    }

    // Business logic validation
    const canEnrich = hasValidEmail || hasCompany;
    const enrichmentStrategy = this.determineStrategy(hasValidEmail, hasCompany);

    return {
      isValid: errors.length === 0,
      canEnrich,
      enrichmentStrategy,
      errors,
      warnings,
      contactIndex: index,
      fields: {
        hasEmail: !!email,
        hasValidEmail,
        hasCompany: !!hasCompany,
        firstName: !!contact.firstName?.trim(),
        lastName: !!contact.lastName?.trim()
      }
    };
  }

  determineStrategy(hasValidEmail, hasCompany) {
    if (hasValidEmail && hasCompany) return 'VERIFY_AND_DISCOVER';
    if (hasValidEmail) return 'VERIFY_ONLY';
    if (hasCompany) return 'DISCOVER_ONLY';
    return 'NO_ENRICHMENT';
  }

  generateProcessingId() {
    return `proc_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }
}

// Execute validation
try {
  const service = new ContactValidationService();
  const inputData = $input.first().json;

  let contacts = [];
  if (inputData.contacts) {
    contacts = inputData.contacts;
  } else {
    // Handle direct contact input
    contacts = [$input.first().json];
  }

  console.log(`Processing ${contacts.length} contacts for validation`);
  const validatedContacts = service.validateContacts(contacts);

  const summary = {
    total: validatedContacts.length,
    valid: validatedContacts.filter(c => c.validation.isValid).length,
    canEnrich: validatedContacts.filter(c => c.validation.canEnrich).length,
    strategies: {}
  };

  validatedContacts.forEach(c => {
    const strategy = c.validation.enrichmentStrategy;
    summary.strategies[strategy] = (summary.strategies[strategy] || 0) + 1;
  });

  console.log('Validation Summary:', summary);

  return validatedContacts.map(contact => ({ json: contact }));

} catch (error) {
  console.error('Validation failed:', error);
  return [{
    json: {
      error: true,
      errorType: 'VALIDATION_ERROR',
      message: error.message,
      timestamp: new Date().toISOString()
    }
  }];
}

// Domain Service: Email Verification
class EmailVerificationService {
  constructor() {
    this.timeoutMs = 10000;
  }

  async verifyEmail(contact) {
    const email = contact.email?.trim();
    if (!email) {
      return this.createVerificationResult(contact, 'NO_EMAIL', null);
    }

    try {
      const verificationResult = await this.simulateMailcheckAPI(email);
      return this.createVerificationResult(contact, 'VERIFIED', verificationResult);

    } catch (error) {
      console.warn(`Email verification failed for ${email}: ${error.message}`);
      return this.createVerificationResult(contact, 'VERIFICATION_FAILED', null, error);
    }
  }

  async simulateMailcheckAPI(email) {
    const domain = email.split('@')[1];
    const commonDomains = ['gmail.com', 'outlook.com', 'yahoo.com', 'microsoft.com', 'google.com', 'apple.com', 'netflix.com', 'adobe.com', 'spotify.com', 'salesforce.com', 'tesla.com'];

    if (email.includes('invalid') || email.includes('fake')) {
      return {
        deliverable: false,
        trustRate: 5,
        mxExists: false,
        smtpExists: false,
        reason: 'Invalid email format or suspicious patterns'
      };
    }

    if (commonDomains.includes(domain)) {
      return {
        deliverable: true,
        trustRate: 85,
        mxExists: true,
        smtpExists: true,
        reason: 'Common domain with good reputation'
      };
    }

    return {
      deliverable: true,
      trustRate: 70,
      mxExists: true,
      smtpExists: false,
      reason: 'Domain exists but SMTP check inconclusive'
    };
  }

  createVerificationResult(contact, status, apiResult, error = null) {
    const result = {
      ...contact,
      emailVerification: {
        status,
        verifiedAt: new Date().toISOString(),
        originalEmail: contact.email,
        error: error?.message || null
      }
    };

    if (apiResult) {
      result.emailVerification = {
        ...result.emailVerification,
        deliverable: apiResult.deliverable,
        trustRate: apiResult.trustRate,
        mxExists: apiResult.mxExists,
        smtpExists: apiResult.smtpExists,
        verificationReason: apiResult.reason,
        isHighConfidence: apiResult.trustRate > 70 && apiResult.mxExists
      };
    }

    return result;
  }
}

