// Domain Service: Domain Discovery
class DomainDiscoveryService {
  constructor() {
    this.timeoutMs = 15000;
    this.maxRetries = 2;
  }

  async discoverDomain(contact) {
    const company = contact.company?.trim();
    if (!company) {
      return this.createDiscoveryResult(contact, 'NO_COMPANY', null);
    }

    try {
      const discoveryResult = await this.searchCompanyDomain(company, contact);
      return this.createDiscoveryResult(contact, 'DISCOVERED', discoveryResult);

    } catch (error) {
      console.warn(`Domain discovery failed for ${company}: ${error.message}`);
      return this.createDiscoveryResult(contact, 'DISCOVERY_FAILED', null, error);
    }
  }

  async searchCompanyDomain(company, contact) {
    const normalizedCompany = this.normalizeCompanyName(company);

    const domainMappings = {
      'microsoft': { domain: 'microsoft.com', confidence: 95 },
      'google': { domain: 'google.com', confidence: 95 },
      'amazon': { domain: 'amazon.com', confidence: 95 },
      'apple': { domain: 'apple.com', confidence: 95 },
      'salesforce': { domain: 'salesforce.com', confidence: 90 },
      'meta': { domain: 'meta.com', confidence: 85 },
      'tesla': { domain: 'tesla.com', confidence: 90 },
      'netflix': { domain: 'netflix.com', confidence: 85 },
      'adobe': { domain: 'adobe.com', confidence: 90 },
      'spotify': { domain: 'spotify.com', confidence: 85 }
    };

    const mapping = domainMappings[normalizedCompany];
    if (!mapping) {
      throw new Error(`No domain found for company: ${company}`);
    }

    let suggestedEmail = null;
    if (contact.firstName && contact.lastName) {
      const firstName = contact.firstName.toLowerCase();
      const lastName = contact.lastName.toLowerCase();
      suggestedEmail = `${firstName}.${lastName}@${mapping.domain}`;
    }

    return {
      primaryDomain: mapping.domain,
      confidence: mapping.confidence,
      suggestedEmail,
      searchMethod: 'company_lookup',
      organization: {
        name: company,
        normalizedName: normalizedCompany,
        domain: mapping.domain
      }
    };
  }

  normalizeCompanyName(company) {
    return company
      .toLowerCase()
      .replace(/\b(corporation|corp|inc|llc|ltd|company|co|group)\b/g, '')
      .replace(/[^a-z0-9\s]/g, '')
      .trim()
      .split(' ')[0];
  }

  createDiscoveryResult(contact, status, apiResult, error = null) {
    const result = {
      ...contact,
      domainDiscovery: {
        status,
        discoveredAt: new Date().toISOString(),
        searchedCompany: contact.company,
        error: error?.message || null
      }
    };

    if (apiResult) {
      result.domainDiscovery = {
        ...result.domainDiscovery,
        primaryDomain: apiResult.primaryDomain,
        confidence: apiResult.confidence,
        suggestedEmail: apiResult.suggestedEmail,
        searchMethod: apiResult.searchMethod,
        organization: apiResult.organization,
        isHighConfidence: apiResult.confidence > 80
      };
    }

    return result;
  }
}

