// Domain Service: Enrichment Orchestrator
class EnrichmentOrchestrator {
  constructor() {
    this.qualityThresholds = {
      email: {
        minTrustRate: 50,
        requireMxExists: true
      },
      domain: {
        minConfidence: 70
      }
    };
  }

  orchestrateEnrichment(contacts) {
    console.log(`Orchestrating enrichment for ${contacts.length} contacts`);

    return contacts.map(contact => {
      const enrichmentResult = {
        ...contact,
        enrichment: {
          processedAt: new Date().toISOString(),
          processingId: contact.processingId,
          strategy: contact.validation.enrichmentStrategy,
          qualityScore: 0,
          confidence: 'LOW',
          finalEmail: null,
          finalDomain: null,
          enrichmentSource: null,
          businessDecision: null,
          auditTrail: []
        }
      };

      this.processEmailVerification(enrichmentResult);
      this.processDomainDiscovery(enrichmentResult);
      this.applyBusinessRules(enrichmentResult);
      this.calculateQualityScore(enrichmentResult);

      return enrichmentResult;
    });
  }

  processEmailVerification(result) {
    const verification = result.emailVerification;
    if (!verification) return;

    result.enrichment.auditTrail.push({
      step: 'email_verification',
      status: verification.status,
      timestamp: verification.verifiedAt
    });

    if (verification.status === 'VERIFIED' && verification.deliverable) {
      const meetsThreshold = verification.trustRate >= this.qualityThresholds.email.minTrustRate &&
                           (!this.qualityThresholds.email.requireMxExists || verification.mxExists);

      if (meetsThreshold) {
        result.enrichment.finalEmail = result.email;
        result.enrichment.enrichmentSource = 'original_verified';
        result.enrichment.auditTrail.push({
          step: 'email_quality_check',
          result: 'passed',
          trustRate: verification.trustRate,
          timestamp: new Date().toISOString()
        });
      }
    }
  }

  processDomainDiscovery(result) {
    const discovery = result.domainDiscovery;
    if (!discovery) return;

    result.enrichment.auditTrail.push({
      step: 'domain_discovery',
      status: discovery.status,
      timestamp: discovery.discoveredAt
    });

    if (discovery.status === 'DISCOVERED' && discovery.isHighConfidence) {
      result.enrichment.finalDomain = discovery.primaryDomain;

      if (!result.enrichment.finalEmail && discovery.suggestedEmail) {
        result.enrichment.finalEmail = discovery.suggestedEmail;
        result.enrichment.enrichmentSource = 'domain_suggested';
        result.enrichment.auditTrail.push({
          step: 'email_suggestion',
          suggestedEmail: discovery.suggestedEmail,
          confidence: discovery.confidence,
          timestamp: new Date().toISOString()
        });
      }
    }
  }

  applyBusinessRules(result) {
    const hasVerifiedEmail = result.enrichment.enrichmentSource === 'original_verified';
    const hasSuggestedEmail = result.enrichment.enrichmentSource === 'domain_suggested';
    const hasDomain = !!result.enrichment.finalDomain;

    if (hasVerifiedEmail && hasDomain) {
      result.enrichment.businessDecision = 'FULLY_ENRICHED';
      result.enrichment.confidence = 'HIGH';
    } else if (hasVerifiedEmail) {
      result.enrichment.businessDecision = 'EMAIL_VERIFIED';
      result.enrichment.confidence = 'MEDIUM';
    } else if (hasSuggestedEmail && hasDomain) {
      result.enrichment.businessDecision = 'EMAIL_SUGGESTED';
      result.enrichment.confidence = 'MEDIUM';
    } else if (hasDomain) {
      result.enrichment.businessDecision = 'DOMAIN_ONLY';
      result.enrichment.confidence = 'LOW';
    } else {
      result.enrichment.businessDecision = 'NO_ENRICHMENT';
      result.enrichment.confidence = 'NONE';
    }

    result.enrichment.auditTrail.push({
      step: 'business_decision',
      decision: result.enrichment.businessDecision,
      confidence: result.enrichment.confidence,
      timestamp: new Date().toISOString()
    });
  }

  calculateQualityScore(result) {
    let score = 0;

    const verification = result.emailVerification;
    if (verification?.status === 'VERIFIED' && verification.deliverable) {
      score += Math.min(40, verification.trustRate * 0.4);
    }

    const discovery = result.domainDiscovery;
    if (discovery?.status === 'DISCOVERED') {
      score += Math.min(30, discovery.confidence * 0.3);
    }

    let completeness = 0;
    if (result.firstName) completeness += 7.5;
    if (result.lastName) completeness += 7.5;
    if (result.company) completeness += 7.5;
    if (result.enrichment.finalEmail) completeness += 7.5;
    score += completeness;

    result.enrichment.qualityScore = Math.round(score);

    result.enrichment.auditTrail.push({
      step: 'quality_scoring',
      score: result.enrichment.qualityScore,
      timestamp: new Date().toISOString()
    });
  }
}

