// Domain Service: Result Categorization
class ResultCategorizationService {
  categorizeResults(contacts) {
    const categories = {
      fullyEnriched: [],
      emailVerified: [], 
      emailSuggested: [],
      domainOnly: [],
      noEnrichment: [],
      errors: []
    };

    const summary = {
      totalProcessed: contacts.length,
      successRate: 0,
      averageQualityScore: 0,
      processingTime: new Date().toISOString()
    };

    contacts.forEach(contact => {
      if (contact.error || contact.enrichment?.status?.includes('ERROR')) {
        categories.errors.push(contact);
        return;
      }

      const decision = contact.enrichment?.businessDecision;

      switch (decision) {
        case 'FULLY_ENRICHED':
          categories.fullyEnriched.push(contact);
          break;
        case 'EMAIL_VERIFIED':
          categories.emailVerified.push(contact);
          break;
        case 'EMAIL_SUGGESTED':
          categories.emailSuggested.push(contact);
          break;
        case 'DOMAIN_ONLY':
          categories.domainOnly.push(contact);
          break;
        default:
          categories.noEnrichment.push(contact);
      }
    });

    const successfulEnrichments = categories.fullyEnriched.length + 
                                 categories.emailVerified.length + 
                                 categories.emailSuggested.length;

    summary.successRate = contacts.length > 0 ? 
      Math.round((successfulEnrichments / contacts.length) * 100) : 0;

    const qualityScores = contacts
      .filter(c => c.enrichment?.qualityScore)
      .map(c => c.enrichment.qualityScore);

    summary.averageQualityScore = qualityScores.length > 0 ?
      Math.round(qualityScores.reduce((a, b) => a + b, 0) / qualityScores.length) : 0;

    summary.categoryCounts = {
      fullyEnriched: categories.fullyEnriched.length,
      emailVerified: categories.emailVerified.length,
      emailSuggested: categories.emailSuggested.length,
      domainOnly: categories.domainOnly.length,
      noEnrichment: categories.noEnrichment.length,
      errors: categories.errors.length
    };

    return {
      categories,
      summary,
      processedAt: new Date().toISOString()
    };
  }
}

